{"path": "res://systems/state_machine.gd", "content": "class_name StateMachine
extends Node

@export var initial_state: State

var current_state: State
var states: Dictionary = {}

func _ready() -> void:
	# 等待一帧确保所有子节点都 ready 了
	await owner.ready

	for child in get_children():
		if child is State:
			states[child.name.to_lower()] = child
			child.transitioned.connect(on_child_transition)
			child.entity = owner

	if initial_state:
		current_state = initial_state
		current_state.enter()

func _process(delta: float) -> void:
	if current_state:
		current_state.update(delta)

func _physics_process(delta: float) -> void:
	if current_state:
		current_state.physics_update(delta)

func on_child_transition(state: State, new_state_name: String) -> void:
	if state != current_state:
		return

	var new_state = states.get(new_state_name.to_lower())
	if not new_state:
		printerr("StateMachine: State '%s' does not exist." % new_state_name)
		return

	if current_state:
		current_state.exit()

	new_state.enter()
	current_state = new_state

## 强制切换到指定状态（用于外部触发）
func transition_to(state_name: String) -> void:
	var new_state = states.get(state_name.to_lower())
	if not new_state:
		printerr("StateMachine: State '%s' does not exist." % state_name)
		return

	if current_state:
		current_state.exit()

	new_state.enter()
	current_state = new_state
"}

{"content": "extends State
class_name PlayerIdleState

func enter() -> void:
	# 停止移动
	if entity is CharacterBody2D:
		entity.velocity = Vector2.ZERO

func physics_update(_delta: float) -> void:
	var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")

	# 检测各动作
	if input_dir.length() > 0.1:
		transitioned.emit(self, "move")
		return

	if Input.is_action_just_pressed("dodge"):
		transitioned.emit(self, "dodge")
		return

	if Input.is_action_just_pressed("attack"):
		transitioned.emit(self, "attack")
		return

	if Input.is_action_just_pressed("skill"):
		transitioned.emit(self, "skill")
		return
", "path": "res://entities/player/states/idle.gd"}

{"content": "extends State
class_name PlayerMoveState

func enter() -> void:
	pass

func physics_update(delta: float) -> void:
	var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")

	if input_dir.length() < 0.1:
		transitioned.emit(self, "idle")
		return

	# 设置移动速度
	entity.velocity = input_dir * entity.move_speed
	entity.move_and_slide()

	# 更新朝向（用于攻击/技能方向）
	if input_dir.length() > 0.1:
		entity.facing_direction = input_dir

	# 检测动作
	if Input.is_action_just_pressed("dodge"):
		transitioned.emit(self, "dodge")
		return

	if Input.is_action_just_pressed("attack"):
		transitioned.emit(self, "attack")
		return

	if Input.is_action_just_pressed("skill"):
		transitioned.emit(self, "skill")
		return
