{"content": "extends CharacterBody2D
class_name Player

## 移动参数
@export var move_speed: float = 300.0

## 攻击参数
@export var attack_range: float = 40.0
@export var attack_damage: int = 10

## 技能参数
@export var skill_scene: PackedScene  # 在 Inspector 中拖入 Fireball.tscn

## 当前朝向（用于攻击/技能方向）
var facing_direction: Vector2 = Vector2.DOWN

## 引用
@onready var sprite: Sprite2D = $Sprite2D
@onready var animation_player: AnimationPlayer = $AnimationPlayer
@onready var attack_hitbox: Area2D = $AttackHitbox
@onready var state_machine: StateMachine = $StateMachine

func _ready() -> void:
	# 初始执行一次移动检测，避免卡在 idle
	pass

## 执行近战攻击
func perform_melee_attack() -> void:
	# 设置攻击判定框的位置
	attack_hitbox.position = facing_direction * attack_range
	# 触发攻击动画
	if animation_player.has_animation("attack"):
		animation_player.play("attack")
	# 启用攻击碰撞检测（短暂开启）
	attack_hitbox.monitoring = true
	# 用计时器关闭
	await get_tree().create_timer(0.15).timeout
	attack_hitbox.monitoring = false
	attack_hitbox.position = Vector2.ZERO

## 释放技能
func cast_skill() -> void:
	if skill_scene == null:
		return

	var skill_instance = skill_scene.instantiate() as Node2D
	get_tree().current_scene.add_child(skill_instance)

	# 设置技能位置和方向
	skill_instance.global_position = global_position + facing_direction * 20.0
	if skill_instance.has_method("set_direction"):
		skill_instance.set_direction(facing_direction)

	# 触发技能动画
	if animation_player.has_animation("skill"):
		animation_player.play("skill")
", "path": "res://entities/player/player.gd"}

{"content": "extends Area2D
class_name Fireball

@export var speed: float = 500.0
@export var damage: int = 25
@export var lifetime: float = 3.0

var direction: Vector2 = Vector2.DOWN
var time_alive: float = 0.0

func _ready() -> void:
	# 自动销毁
	await get_tree().create_timer(lifetime).timeout
	queue_free()

func set_direction(dir: Vector2) -> void:
	direction = dir.normalized()
	rotation = direction.angle()

func _physics_process(delta: float) -> void:
	position += direction * speed * delta

	# 碰撞检测（手动检测，因为 Area2D 不会自动移动）
	var space_state = get_world_2d().direct_space_state
	var query = PhysicsRayQueryParameters2D.create(global_position, global_position + direction * speed * delta)
	query.exclude = [self]
	var result = space_state.intersect_ray(query)
	if result:
		_on_hit(result)

func _on_hit(hit_info: Dictionary) -> void:
	if hit_info.collider.has_method("take_damage"):
		hit_info.collider.take_damage(damage)
	# 爆炸效果（后续可增加粒子）
	queue_free()
", "path": "res://skills/fireball.gd"}

