{"path": "res://systems/input_setup.gd", "content": "extends Node
## 自动注册输入映射（避免手动配置 Input Map）

func _enter_tree() -> void:
	_setup_action("move_left", KEY_A, "Left Arrow")
	_setup_action("move_right", KEY_D, "Right Arrow")
	_setup_action("move_up", KEY_W, "Up Arrow")
	_setup_action("move_down", KEY_S, "Down Arrow")
	_setup_action("dodge", KEY_SPACE)
	_setup_action("attack", MOUSE_BUTTON_LEFT)
	_setup_action("skill", MOUSE_BUTTON_RIGHT)

func _setup_action(action_name: String, primary_key: Variant, secondary_key: Variant = -1) -> void:
	if InputMap.has_action(action_name):
		return

	InputMap.add_action(action_name)

	var event_primary: InputEvent
	if primary_key is Key:
		event_primary = InputEventKey.new()
		event_primary.keycode = primary_key
	elif primary_key is MouseButton:
		event_primary = InputEventMouseButton.new()
		event_primary.button_index = primary_key

	if event_primary:
		InputMap.action_add_event(action_name, event_primary)

	if secondary_key != -1:
		var event_secondary = InputEventKey.new()
		event_secondary.keycode = secondary_key
		InputMap.action_add_event(action_name, event_secondary)
"}

